const source = $('Get Bear Data Values').first().json;

const textbelt = $input.first().json;

return [{

  json: {

    name: source.name,

    status: source.status,

    quota: source.quota,

    harvest_to_date: source.harvest_to_date,

    remaining: source.remaining,

    timestamp: source.timestamp,

    text_sent: textbelt.success,

    text_id: textbelt.textId,

    quota_remaining_after_send: textbelt.quotaRemaining

  }

}];

const weather = JSON.parse($json.data);

const periods = weather.properties.periods || [];

// Take first 24 hourly forecast periods returned by NWS

const next24Raw = periods.slice(0, 24);

// Use the first forecast hour as the label source

const firstStartRaw = next24Raw[0]?.startTime;

if (!firstStartRaw) {

  throw new Error("No hourly forecast periods found from NWS.");

}

const firstStart = new Date(firstStartRaw);

// Format date/time in Mountain Time

const dateLabel = new Intl.DateTimeFormat("en-US", {

  timeZone: "America/Denver",

  month: "numeric",

  day: "numeric",

}).format(firstStart);

const timeLabel = new Intl.DateTimeFormat("en-US", {

  timeZone: "America/Denver",

  hour: "numeric",

  hour12: true,

})

  .format(firstStart)

  .toLowerCase()

  .replace(/\s/g, "");

// Clean forecast rows for Claude

const next24 = next24Raw.map(p => ({

  time: p.startTime,

  temp: `${p.temperature} ${p.temperatureUnit}`,

  precipChance: p.probabilityOfPrecipitation?.value ?? 0,

  wind: `${p.windSpeed} ${p.windDirection}`,

  forecast: p.shortForecast

}));

return [{

  json: {

    weather_location: "Sample Location",

    forecast_label: `24hr Fcst - ${dateLabel} ${timeLabel}`,

    debug_first_raw_time: firstStartRaw,

    debug_forecast_label: `24hr Fcst - ${dateLabel} ${timeLabel}`,

    debug_total_periods_from_nws: periods.length,

    weather_periods: next24

  }

}];

const row = $input.first().json;

const now = new Date();

const date = now.toLocaleDateString('en-US', {

  timeZone: 'America/Denver'

});

const time = now.toLocaleTimeString('en-US', {

  timeZone: 'America/Denver',

  hour: 'numeric',

  minute: '2-digit'

});

const message = [

  `Date: ${date}`,

  `Time: ${time} MT`,

  `Unit: ${row.name}`,

  `Status: ${row.status}`,

  `Quota: ${row.quota}`,

  `Harvest to date: ${row.harvest_to_date}`,

  `Remaining: ${row.remaining}`

].join('\n');

return [{

  json: {

    message

  }

}];

const html = $input.first().json.data;

const match = html.match(

  /Beat Unit[\s\S]{0,500}?(Open|Closed)[\s\S]{0,100}?(\d+)[\s\S]{0,100}?(\d+)[\s\S]{0,100}?(\d+)/

);

if (!match) {

  throw new Error("Could not find Bear Hunt");

}

return [{

  json: {

    name: "Bear Hunt",

    status: match[1],

    quota: Number(match[2]),

    harvest_to_date: Number(match[3]),

    remaining: Number(match[4]),

    timestamp: new Date().toISOString()



  }

}];
